sys_script_fix.script:
// get all OUs
var grAllOUs = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
grAllOUs.query();

while(grAllOUs.next()){
	var ouName;
	try {
		ouName = grAllOUs.getValue("office_name");

		if(grAllOUs.u_top_ou == grAllOUs.getUniqueValue()){
			// update the Task Administrator Field for this OU
			new OrganizationalScripts().setTopOUTaskAdministrators(grAllOUs);
		} else {
			// clear the Task Adminstrator field, this is not a top OU
			grAllOUs.u_global_authorities = "";
			grAllOUs.update("Fix Script 2.8.3 - only top OU needs Administrator list");
		}
		var org_privacy = grAllOUs.getValue("u_organizational_privacy");
		// STRY0141376 
		if(!org_privacy || org_privacy == ''){
			grAllOUs.u_organizational_privacy = "open";
			grAllOUs.update("Fix Script 2.8.3 - default all existing OU to Open Organizational Structures");
		}
	} catch(e){
		gs.error("OU Name:" + ouName + " - Error in '2.8.3 Fix Script Task Admin / OU Privacy' - exception: " + e);
	}		
}
